// ===== LOGOS PARA PDFs =====
// Convierte tus logos a Base64 en: https://base64.guru/converter/encode/image


const logosEscuela = {

  logoIzquierdo: "data:image/png;base64,",
  logoDerecho: "data:image/png;base64,",
  logoSep: "data:image/png;base64,",
  //derecho es poli

  
  // Configuración de logos
  config: {
    // Logo izquierdo
    izq: {
      x: 15,      // Posición X (mm desde la izquierda)
      y: 5,       // Posición Y (mm desde arriba)
      ancho: 19,  // Ancho en mm
      alto: 19    // Alto en mm
    },
    // Logo derecho
    der: {
      x: 149,     // Posición X
      y: 7,       // Posición Y
      ancho: 50,  // Ancho en mm
      alto: 8     // Alto en mm
    }
  },
  
  // Color institucional para PDFs (RGB)
  colorInstitucional: {
    hex: '#6C1D45',
    rgb: [108, 29, 69]  // Conversión de #6C1D45 a RGB
  }
};

// Función para agregar logos al PDF
function agregarLogosAlPDF(doc, usarLogoSep = false) {
  // Logo izquierdo
  if (logosEscuela.logoIzquierdo &&
      !logosEscuela.logoIzquierdo.includes('iVBORw0KGgoAAAANSUhEUgAAAAUA')) {
    try {
      const cfg = logosEscuela.config.izq;
      doc.addImage(logosEscuela.logoIzquierdo, 'PNG', cfg.x, cfg.y, cfg.ancho, cfg.alto);
    } catch (e) {
      console.log('Error al cargar logo izquierdo:', e);
    }
  }

  // Logo derecho: logoSep para carreras con tieneExamenFinal, logoDerecho para las demás
  const logoDer = (usarLogoSep && logosEscuela.logoSep) ? logosEscuela.logoSep : logosEscuela.logoDerecho;
  if (logoDer && !logoDer.includes('iVBORw0KGgoAAAANSUhEUgAAAAUA')) {
    try {
      const cfg = logosEscuela.config.der;
      doc.addImage(logoDer, 'PNG', cfg.x, cfg.y, cfg.ancho, cfg.alto);
    } catch (e) {
      console.log('Error al cargar logo derecho:', e);
    }
  }
}